exercises.expected_solution:
import java.util.*;
import java.util.stream.*;
class Sale {
    String product, category; int qty; double price;
    Sale(String p, String c, int q, double pr) { product=p; category=c; qty=q; price=pr; }
    double revenue() { return qty * price; }
}
public class App {
    public static void main(String[] args) {
        List<Sale> sales = Arrays.asList(
            new Sale("Mouse",    "Electronics", 5,  799),
            new Sale("Keyboard", "Electronics", 3,  1999),
            new Sale("Java Book","Books",        20, 649),
            new Sale("USB Hub",  "Accessories",  15, 499)
        );

        // Count
        Map<String, Long> counts = sales.stream()
            .collect(Collectors.groupingBy(s -> s.category, Collectors.counting()));
        System.out.println("Counts: " + new TreeMap<>(counts));

        // Revenue
        Map<String, Double> revenue = sales.stream()
            .collect(Collectors.groupingBy(s -> s.category,
                Collectors.summingDouble(Sale::revenue)));
        System.out.println("Revenue: " + new TreeMap<>(revenue));

        // Top category by revenue
        String top = revenue.entrySet().stream()
            .max(Map.Entry.comparingByValue())
            .map(Map.Entry::getKey)
            .orElse("None");
        System.out.println("Top category: " + top);

        // Hit target
        Map<Boolean, List<String>> hitTarget = revenue.entrySet().stream()
            .collect(Collectors.partitioningBy(
                e -> e.getValue() > 10000,
                Collectors.mapping(Map.Entry::getKey, Collectors.toList())
            ));
        hitTarget.forEach((hit, cats) -> Collections.sort(cats));
        System.out.println("Hit target (>₹10000): " + hitTarget);
    }
}

