exercises.expected_solution:
import java.util.*;
import java.util.stream.*;
class Order {
    String id, customerId, status;
    double amount;
    Order(String i, String c, double a, String s) { id=i; customerId=c; amount=a; status=s; }
}
public class App {
    public static void main(String[] args) {
        List<Order> orders = Arrays.asList(
            new Order("O1","C001",1500,"DELIVERED"),
            new Order("O2","C002",3500,"PENDING"),
            new Order("O3","C001",2200,"DELIVERED"),
            new Order("O4","C003", 800,"CANCELLED"),
            new Order("O5","C002",4100,"DELIVERED"),
            new Order("O6","C001", 950,"PENDING")
        );

        // 1. Status counts
        Map<String, Long> statusCounts = orders.stream()
            .collect(Collectors.groupingBy(o -> o.status, Collectors.counting()));
        System.out.println("Status counts: " + new TreeMap<>(statusCounts));

        // 2. Avg value per customer
        Map<String, Double> avgByCustomer = orders.stream()
            .collect(Collectors.groupingBy(o -> o.customerId,
                Collectors.averagingDouble(o -> o.amount)));
        System.out.println("Avg value by customer: " + new TreeMap<>(avgByCustomer));

        // 3. Lookup map
        Map<String, Order> lookupMap = orders.stream()
            .collect(Collectors.toMap(o -> o.id, o -> o));
        System.out.println("Lookup O3 amount: " + lookupMap.get("O3").amount);

        // 4. Partition by value
        Map<Boolean, Long> valueSplit = orders.stream()
            .collect(Collectors.partitioningBy(
                o -> o.amount >= 2000, Collectors.counting()));
        System.out.println("High-value count: " + valueSplit.get(true) +
                           " | Low-value count: " + valueSplit.get(false));

        // 5. Top 2 by order count
        Map<String, Long> orderCount = orders.stream()
            .collect(Collectors.groupingBy(o -> o.customerId, Collectors.counting()));
        List<String> top2 = orderCount.entrySet().stream()
            .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
            .limit(2)
            .map(Map.Entry::getKey)
            .sorted()  // tie-break: sort alphabetically
            .collect(Collectors.toList());
        System.out.println("Top 2 customers by order count: " + top2);
    }
}

